<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #121212;
    --panel: #1e1e1e;
    --accent: #4fc3f7;
    --accent2: #ff7043;
    --text: #e0e0e0;
  }
  body {
    background: var(--bg);
    color: var(--text);
    font-family: 'Segoe UI', Arial, sans-serif;
    margin: 0;
    padding: 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
  }
  h1 {
    font-size: 1.4em;
    margin-bottom: 12px;
  }
  #controls {
    display: flex;
    gap: 10px;
    margin-bottom: 20px;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #444;
    padding: 8px 16px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.95em;
    transition: background 0.15s;
  }
  button:hover {
    background: #2a2a2a;
  }
  button:active {
    background: #333;
  }
  #bars {
    display: flex;
    align-items: flex-end;
    justify-content: center;
    gap: 2px;
    width: 90vw;
    max-width: 900px;
    height: 400px;
    background: var(--panel);
    border-radius: 8px;
    padding: 10px;
    box-sizing: border-box;
  }
  .bar {
    flex: 1 1 auto;
    background: var(--accent);
    border-radius: 2px 2px 0 0;
    transition: height 0.05s linear;
  }
  .bar.compare {
    background: var(--accent2);
  }
  .bar.sorted {
    background: #66bb6a;
  }
  #speed-label {
    color: #999;
    font-size: 0.85em;
    align-self: center;
    margin-left: 10px;
  }
</style>
</head>
<body>
  <h1>Sorting Algorithm Visualizer</h1>
  <div id="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
    <span id="speed-label">Insertion Sort</span>
  </div>
  <div id="bars"></div>

<script>
(function() {
  var ORIGINAL = [];
  var arr = [];
  var barsEl = document.getElementById('bars');

  // Insertion-sort state, driven one step at a time.
  var state = null; // { i, j } where i is the outer index being inserted, j is current compare position

  function randomArray(n) {
    var a = [];
    for (var k = 0; k < n; k++) {
      a.push(Math.floor(Math.random() * 95) + 5);
    }
    return a;
  }

  function resetSortState() {
    // i starts at 1: classic insertion sort
    state = { i: 1, j: 1, active: -1, active2: -1 };
  }

  function render(highlightIdx) {
    barsEl.innerHTML = '';
    var maxVal = Math.max.apply(null, arr.length ? arr : [1]);
    for (var k = 0; k < arr.length; k++) {
      var bar = document.createElement('div');
      bar.className = 'bar';
      var h = (arr[k] / maxVal) * 100;
      bar.style.height = h + '%';
      if (highlightIdx && (k === highlightIdx[0] || k === highlightIdx[1])) {
        bar.classList.add('compare');
      }
      barsEl.appendChild(bar);
    }
  }

  function isSorted() {
    for (var k = 1; k < arr.length; k++) {
      if (arr[k - 1] > arr[k]) return false;
    }
    return true;
  }

  // Performs exactly one comparison/step of insertion sort.
  // Returns true once fully sorted, false otherwise.
  function sortStep() {
    if (!state) resetSortState();

    if (arr.length <= 1) {
      render();
      return true;
    }

    if (state.i >= arr.length) {
      render();
      return true;
    }

    // One step: compare arr[j-1] and arr[j]; swap if needed; move j back or advance i.
    if (state.j > 0 && arr[state.j - 1] > arr[state.j]) {
      var tmp = arr[state.j - 1];
      arr[state.j - 1] = arr[state.j];
      arr[state.j] = tmp;
      render([state.j - 1, state.j]);
      state.j--;
      if (state.j === 0) {
        state.i++;
        state.j = state.i;
      }
    } else {
      render([Math.max(state.j - 1, 0), state.j]);
      state.i++;
      state.j = state.i;
    }

    var done = state.i >= arr.length;
    if (done) render();
    return done;
  }

  function setArray(a) {
    arr = a.slice();
    resetSortState();
    render();
  }

  function shuffle() {
    setArray(randomArray(arr.length || 40));
  }

  function fullReset() {
    setArray(ORIGINAL.slice());
  }

  // Animation driver for the Sort button.
  var animating = false;
  function animateSort() {
    if (animating) return;
    animating = true;
    function step() {
      var done = sortStep();
      if (!done) {
        requestAnimationFrame(function() {
          setTimeout(step, 15);
        });
      } else {
        animating = false;
      }
    }
    step();
  }

  document.getElementById('sort').addEventListener('click', animateSort);
  document.getElementById('shuffle').addEventListener('click', shuffle);
  document.getElementById('reset').addEventListener('click', fullReset);

  ORIGINAL = randomArray(40);
  setArray(ORIGINAL);

  window.viz = {
    array: function() { return arr.slice(); },
    setArray: function(a) { setArray(a); },
    sortStep: function() { return sortStep(); },
    sorted: function() { return isSorted(); }
  };
})();
</script>
</body>
</html>
